#!/usr/bin/perl
use strict;
use warnings;

# Check if the script is being run directly (not included)
if ($0 ne '/path/to/your/script.cgi') {
    print "Content-type: text/plain\n\n";
    exit 1;
}

# Get the redirect URL from the 'next' parameter
my $redirect_url = $ENV{'QUERY_STRING'};
$redirect_url =~ s/^next=//;

# Check if a valid redirect URL was provided
if (!$redirect_url || !$redirect_url =~ m/^[a-zA-Z0-9\/\.\-\_:\?]+$/) {
    print "Content-type: text/plain\n\n";
    print "Invalid redirect URL.";
    exit 1;
}

# Set the HTTP header to redirect the user
print "Status: 302 Found\n";
print "Location $redirect_url\n\n";

exit 0;